+
+/// Free all tracked strings for a handle
+fn freeTrackedStrings(handle: *Handle) void {
+    if (tracked_strings.fetchRemove(handle)) |kv| {
+        var list = kv.value;
+        for (list.items) |str| {
+            allocator.free(str);
+        }
+        list.deinit(allocator);
+    }
